#include <iostream>\n#include <vector>\n#include <set>\n\nclass Graph {\n public:\n  Graph(int n, const std::vector<std::pair<int, int>>& edges) {\n    table_.resize(n + 1);\n    Build(edges);\n  }\n\n  const std::set<int>& GetPoints() {\n    return points_;\n  }\n\n private:\n  void Build(const std::vector<std::pair<int, int>>& edges) {\n    for (const std::pair<int, int>& edge : edges) {\n      table_[edge.first].push_back(edge.second);\n      table_[edge.second].push_back(edge.first);\n    }\n    used_.resize(table_.size(), false);\n    d_.resize(table_.size(), -1);\n    h_.resize(table_.size(), -1);\n    for (int i = 1; i < static_cast<int>(table_.size()); i++) {\n      if (!used_[i]) {\n        Dfs(i);\n      }\n    }\n  }\n\n  void Dfs(int v, int parent = -1) {\n    used_[v] = true;\n    if (parent == -1) {\n      d_[v] = h_[v] = 0;\n    } else {\n      d_[v] = h_[v] = h_[parent] + 1;\n    }\n    int children = 0;\n    for (int u : table_[v]) {\n      if (u == v) {\n        continue;\n      }\n      if (used_[u]) {\n        d_[v] = std::min(d_[v], h_[u]);\n      } else {\n        Dfs(u, v);\n        d_[v] = std::min(d_[v], d_[u]);\n        if (h_[v] <= d_[u] && parent != -1) {\n          points_.insert(v);\n        }\n        children++;\n      }\n    }\n    if (parent == -1 && children > 1) {\n      points_.insert(v);\n    }\n  }\n\n  std::vector<std::vector<int>> table_;\n  std::vector<bool> used_;\n  std::vector<int> h_;\n  std::vector<int> d_;\n  std::set<int> points_;\n};\n\nint main() {\n  int n = 0;\n  int m = 0;\n  std::cin >> n >> m;\n\n  std::vector<std::pair<int, int>> edges(m);\n  for (int i = 0; i < m; i++) {\n    std::cin >> edges[i].first >> edges[i].second;\n  }\n\n  Graph g(n, edges);\n\n  std::cout << g.GetPoints().size() << std::endl;\n  for (int i : g.GetPoints()) {\n    std::cout << i << std::endl;\n  }\n  return 0;\n}